var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"…오늘도 없나?","JPN":"……今日もいないかな？","ENG":"...Is she not home again today?","TWN":"…今天也不在家嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"루 양을 만나러 온 거니?","JPN":"ルーさんに会いに来たのか？","ENG":"Are you here to see Lugh?","TWN":"你是來找露的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"으악, 깜짝아.","JPN":"うわっ、びっくりした。","ENG":"Whoa! You almost scared me to death.","TWN":"啊啊，嚇我一跳。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"할아버지가 왜 여깄어요?","JPN":"なんでおじいちゃんがここにいるんですか？","ENG":"What are you doing here, gramps?","TWN":"奇恩爺爺你怎麼在這裡？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"가게에 주문받은 맞춤옷이 완성돼서 말이다.","JPN":"お店で頼まれた服が完成したからな。","ENG":"I am delivering the finished custom clothes to its owner.","TWN":"店裡訂做的衣服已經完成了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"그런데, 아무래도 집주인이 자릴 비운 모양이구나.","JPN":"ところで、どうやら主が留守中のようだ。","ENG":"But it seems that no one is home at the moment.","TWN":"不過看起來房子的主人不在家呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"나흘째 비어있어요.","JPN":"4日も戻ってきてないんですよ。","ENG":"It's been empty for the last four days.","TWN":"已經空了四天了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"다시 돌아온 줄 알았는데… 착각이었나봐요.","JPN":"今日はいると思ったのに……勘違いだったみたいです。","ENG":"I thought she'd be back by now... but I guess I was wrong.","TWN":"還以為回來了…看來是我搞錯了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"그러고보니, 모르가나 아가씨가 자릴 비운 지도 그쯤 됐지.","JPN":"そういえば、モルガナお嬢様も家を出てそれくらいになるか。","ENG":"Come to think of it, Miss Morgana has also been missing since about that time.","TWN":"說起來，莫甘娜小姐也差不多離開那麼久了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"두 사람은 아마도 중요한 일로 잠시 자릴 비운 걸게다.","JPN":"二人はたぶん、大事な仕事でしばらくいないのだろうよ。","ENG":"I'm sure that both are temporarily absent to do something important.","TWN":"她們二個可能是因為重要的事情暫時離開了吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그럼… 다행이고요, 뭐.","JPN":"それならいいんですけど……","ENG":"Well, that's reassuring to know.","TWN":"那…那就好。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"어머니 건강은 괜찮아지셨니?","JPN":"母は元気になったか？","ENG":"How is your mother?","TWN":"你的媽媽最近好點了嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"이제 목발 짚고 밖에 나올 정도는 되세요.","JPN":"はい。もう松葉杖をついて外に出られるようになりました。","ENG":"She's now able to go out of the house using her crutches.","TWN":"現在已經能拄著拐杖出門了。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"하지만, 언젠가 또 마물이 나타날 수 있다고 생각하면… 안심이 안돼요.","JPN":"でも、またいつ魔物が現われるかと思うと……不安でたまりません。","ENG":"But thinking about how the monster could attack the village again... I don't think it's safe for her.","TWN":"但是，我一想到怪物可能隨時會再出現…就無法安心。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"여기에 온 것도 그런 걱정 때문이겠구나.","JPN":"ここにも心配で来たのだな。","ENG":"So you're here out of concern for your mother, correct?","TWN":"所以你才來這裡找她嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"어쩌면… 마물과 싸우는 법을 배울 수 있지 않을까 해서요.","JPN":"もしかしたら……魔物と戦う方法を教えてもらえるんじゃないかなって。","ENG":"I was wondering... if she could teach me how to fight those monsters.","TWN":"我想…拜託她教我與怪物戰鬥的方法。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"비웃음을 사고 쫓겨날 수도 있겠지만… 그 정도는 각오하고 있어요.","JPN":"笑われて追い返されるかもしれませんが……それは覚悟してます。","ENG":"She might laugh at the idea and kick me out, but... I still think I should ask.","TWN":"就算被嘲笑，被趕走…我也做好了心理準備。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"너도 직접 봤겠지. 루 양이 싸우는 모습을 말이야.","JPN":"お前もその目で見ただろう？　ルーさんが戦っている姿を。","ENG":"You saw how Ms. Lugh fought with your own eyes too.","TWN":"你親眼看到過露戰鬥的樣子吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"동토 너머의 먼나라에서 온 전사라던데, 정말 멋지지 않더냐?","JPN":"凍土の向こうにある遠い国から来た戦士らしいが、勇ましいではないか？","ENG":"She is a warrior from a distant country beyond the gelid lands. Didn't she look so great?","TWN":"露是來自凍土另一邊的戰士，她很強吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"네, 정말 멋지게 마물들을 물리쳤어요.","JPN":"はい、魔物たちをやっつける姿は本当にかっこよかったです。","ENG":"Yeah, she really gave those monsters a beating.","TWN":"很強，三兩下就解決掉怪物…"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그 사람이 빛난다고 느껴질 만큼.","JPN":"眩しいくらいに輝いていました。","ENG":"I could almost see an aura around her.","TWN":"感覺她就像在發光一樣。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그 사람에게 빚을 갚고 싶은데… 어떻게 해야할지 모르겠어요.","JPN":"あの人に恩返ししたいのに……どうしたらいいかわからなくて。","ENG":"I want to repay her somehow... but I don't know what to do.","TWN":"我想報答她…但不知道該怎麼做。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"전 마물과 싸우는 법도 모르니까… 앞으로도 성자에게 도움만 받게 되겠죠.","JPN":"僕は魔物と戦う術も知らないし……これからもずっと聖者に助けてもらうしかないのでしょうね。","ENG":"Because I don't know how to fight monsters... and I'll have to rely on Helgons for protection.","TWN":"我連怎麼與怪物戰鬥都不知道…以後也只能依靠聖者的幫助。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"글쎄. 그건 네가 어떤 노력을 하느냐에 달렸지.","JPN":"さあな。それはお前がどんな努力をするかにかかっているさ。","ENG":"Hmm, I think it's up to how much effort you are willing to put into it.","TWN":"這取決於你如何努力。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"전 애초에 성자도 아니잖아요.","JPN":"だって僕はそもそも聖者でもないでしょう？","ENG":"But I'm not even a Helgon.","TWN":"我本來就不是聖者。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그 사람이 마물과 싸우는 걸 보면서, 제가 얼마나 작고 연약한 존재인지 깨달았어요.","JPN":"あの人が魔物と戦う姿を見て、僕がどんなに小さくて弱い存在なのか思い知らされました。","ENG":"Seeing her fight made me realize how small and weak I am.","TWN":"看到那個人與怪物戰鬥，我才意識到自己是多麼地渺小和脆弱。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"그야 넌 작고 연약한 꼬맹이가 맞으니까.","JPN":"そりゃ、お前は小さくて弱いガキだからな。","ENG":"That's because you are just a small and weak kid.","TWN":"因為你確實還很渺小和脆弱沒錯。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그, 그런 뜻이 아니잖아요!","JPN":"そ、そういう意味じゃありませんよ！","ENG":"Th-that's not what I'm talking about!","TWN":"我…我不是那個意思！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"성자들은 굳이 우리가 돕지 않아도 뭐든 혼자서 다 잘해낼 거라고요.","JPN":"聖者たちは僕たちの手なんて借りなくても自分たちで解決してしまう。","ENG":"Helgons can do anything by themselves and don't need our help.","TWN":"聖者們就算沒有我們的幫助，也能獨自完成一切。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"제가 할 수 있는 건… 아무것도 없을 거예요.","JPN":"僕にできることなんて……何もないんです。","ENG":"There's... nothing that I can do.","TWN":"我能做的…恐怕什麼都沒有。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"카롤리스.","JPN":"カロリス。","ENG":"Karolis.","TWN":"卡羅黎斯。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"넌 앞으로도 성자가 될 수는 없을 거다.","JPN":"お前はこれからも聖者にはなれない。","ENG":"You will never be able to become a Helgon.","TWN":"你將來也無法成為聖者。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"쳇… 알고 있어요.","JPN":"ちっ……わかってますよ。","ENG":"Tch... I know that much.","TWN":"嘖…我知道。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"하지만 그게 성자가 우리와 다른 존재라는 뜻은 아니야.","JPN":"だが、だからといって聖者が私たちとは違う存在であるというわけではないのだよ。","ENG":"But that does not mean that they are different beings from us.","TWN":"但這並不表示聖者和我們是不同的存在。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"그들도 우리와 똑같은 감정을 느끼는 사람이니까.","JPN":"彼らも私たちと同じ感情を持つ人間なのだから。","ENG":"They are also humans who have the same emotions as us.","TWN":"她們也是和我們一樣擁有感情的人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"평범한 사람의 말과 행동에 똑같이 상처받고, 그 상처는 제아무리 성자라도 쉽게 회복할 수 없지.","JPN":"普通の人間の言葉や態度に傷ついて、その傷はいくら聖者でも簡単に回復することはできない。","ENG":"They get equally hurt by the actions and words of ordinary people, and not even a Helgon will be able to recover easily from such wounds.","TWN":"她們也會因為普通人的言行而受傷，而這種傷害就算是聖者也難以輕易恢復。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"아…….","JPN":"あ……","ENG":"Ah…","TWN":"呃…"},"stage":{"bg":"ROOT_02","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"그건 반대로 말해, 평범한 사람이 성자에게 큰 영향을 줄 수 있다는 뜻이기도 하단다.","JPN":"それは逆に言うと、普通の人間が聖者に大きな影響を及ぼすこともできるという意味さ。","ENG":"What I'm trying to say is that even an ordinary person can have a great influence on Helgons.","TWN":"反過來說，這也表示普通人可以對聖者產生巨大的影響。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"성자에 비하면 대단치 않은 힘을 가진 존재라 해도, 그 말과 행동이 가져오는 영향은 결코 사소하지 않아.","JPN":"聖者に比べれば非力な存在だとしても、その言葉と行動がもたらす影響は決して小さくはないのだ。","ENG":"Even if we are relatively weak, the power of our words and actions is by no means trivial.","TWN":"就算是比起聖者力量微不足道的存在，他們的言行帶來的影響也絕不容小覷。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그럼 저도, 그 사람에게 도움이 될 수 있을까요?","JPN":"じゃあ僕も、あの人の役に立てるのでしょうか？","ENG":"Then, do you think I can be of help to her?","TWN":"那我也能幫助那個人嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"네가 진정으로 바란다면 얼마든지.","JPN":"お前が心から望むのなら、いくらでもな。","ENG":"If you truly wish it, yes.","TWN":"如果你真心願意的話，當然可以。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"지금은 성자들이 우릴 지켜주고 있지만… 언젠가 그 반대의 상황이 올 수도 있을 테니까.","JPN":"今は聖者が私たちを守ってくれているが……いつかその逆の状況が来るかもしれないだろう。","ENG":"The Helgons might be protecting us now, but... a day will come when we will have to protect them.","TWN":"現在是聖者在保護我們…但總有一天，情況可能會完全反過來。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그렇게 해서라도…","JPN":"そうしてでも……","ENG":"I think it'll be nice...","TWN":"那樣就好…"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그 사람들이 짊어진 책임의 무게를 나눌 수 있다면 좋겠네요.","JPN":"あの人たちが背負っている責任を分かち合えたらいいですね。","ENG":"to be able to share their burden of responsibility like that.","TWN":"如果能分擔一些她們肩上的重擔就好了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"하늘에 빛이…?","JPN":"空に光が……？","ENG":"A light from the sky...?","TWN":"咦？天空中的一閃一閃的…？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"별인가?","JPN":"星かな？","ENG":"Is it a star?","TWN":"是星星嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"꺄악?!","JPN":"キャーッ！？","ENG":"Kyaak!","TWN":"啊？！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"}}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"떨어진다!","JPN":"落ちる！","ENG":"It's falling!","TWN":"要掉下來了！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아야야…","JPN":"いたた……","ENG":"Oww...","TWN":"啊啊啊…"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"루, 괜찮아?","JPN":"ルー、大丈夫？","ENG":"Lugh, are you all right?","TWN":"露，你沒事吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…네, 괜찮은 것 같아요.","JPN":"……はい、大丈夫だと思います。","ENG":"...Yes, I think I'm good.","TWN":"…嗯，好像沒事。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"다행히 푹신한 곳에 떨어져서…","JPN":"幸いふかふかのところに落ちて……","ENG":"I'm glad I landed on something soft–","TWN":"幸好落在柔軟的地方…"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…푹신?","JPN":"……ふかふか？","ENG":"...Soft?","TWN":"…柔軟的地方？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"컥…","JPN":"がっ…","ENG":"Kuh...","TWN":"咳…"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"이런! 카롤리스!","JPN":"おっと！　カロリス！","ENG":"Oh my! Karolis!","TWN":"卡羅黎斯！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"꼬맹이는 무사할 거야.","JPN":"チビちゃんは大丈夫よ。","ENG":"The boy will be fine.","TWN":"這孩子會沒事的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"카롤리스 위로 떨어진 게 귀염둥이가 아니라서 큰 부상은 면했다네.","JPN":"カロリスの上に落ちたのが可愛子ちゃんじゃなくて、幸いだったわね。","ENG":"He avoided serious injury as cutie did not fall on top of him.","TWN":"幸好砸下來的不是小可愛，所以沒受重傷。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그, 그렇게 말하면 내가 더 무거운 것처럼 들리잖아! 내 무기가 무겁기 때문이라고 정확히 짚어야지!","JPN":"そ、そう言うとあたしの方が重いみたいじゃないの！　重いのは武器のせいだってちゃんと説明しなさいよね！","ENG":"Th-that makes it sound like I'm heavier! At least be more precise and say that it's because my weapon is heavy!","TWN":"什…什麼呀！聽起來好像我更重一樣！我只是武器重而已！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"휴, 그래도 많이 안 다쳤다니 정말 다행이네요.","JPN":"ふう、でも大怪我はしてなくて本当によかったですね。","ENG":"Phew, I'm relieved to hear that he wasn't seriously hurt.","TWN":"呼，沒受重傷真是太好了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그래서, 좀 전의 얘길 마저하자면…","JPN":"それで、またさっきの話に戻るけど……","ENG":"So, to continue our conversation...","TWN":"所以，接著剛才的話題…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너희가 돌아오기 직전, 그곳에서 강렬한 역병 에너지가 감지됐어.","JPN":"アナタたちが戻ってくる直前に、あそこから強烈な疫病エネルギーを感知したわ。","ENG":"Just seconds before you returned, an intense plague energy was detected there.","TWN":"就在你們回來之前，那地方檢測到了強烈的瘟疫能量。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"마지막에 뭘 본 건지 말해주겠니?","JPN":"最後に何を見たのか、話してくれる？","ENG":"Can you tell me what the last thing you saw was?","TWN":"能告訴我最後看到了什麼嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"남부에서 봤던 그 호박머리 악마였어.","JPN":"南部で見たあのカボチャ頭の悪魔がいたんだ。","ENG":"It was the pumpkin-head devil that we saw in the South.","TWN":"是我們在南部見過的那個南瓜頭魔鬼。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"자기가 맡은 죄수를 멋대로 풀어줘서 심술이 난 모양이더라고.","JPN":"自分が管理している囚人をあたしたちが勝手に解放して、怒ってるみたいだった。","ENG":"I think he got grumpy because we set one of his prisoners free.","TWN":"似乎因為我們釋放了他負責的囚犯而生氣。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"죄수를 풀어줬다고…?","JPN":"囚人を解放した……？","ENG":"You set a prisoner free...?","TWN":"囚犯…？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"우리도 그게 죄수인지는 정확히 몰라.","JPN":"あたしたちもあれが囚人なのかはっきりはわからないの。","ENG":"We're not actually sure if she was a prisoner or not.","TWN":"我們也不確定那是不是囚犯。"},"stage":{"bg":"SS_SHADOW_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"비명을 지르면서 싸우는 게 좀 무섭긴 해도 엄청 강하고… 딱히 악의를 품고 있진 않았어.","JPN":"雄叫びをあげて戦ってる姿はたしかに怖かったけど、すごく強いし……別に悪意は感じなかった。","ENG":"It was pretty scary to see her scream while fighting, but she was super strong... And she didn't seem to harbor any malice.","TWN":"雖然在戰鬥時的叫聲有點嚇人，但她很厲害…並且沒有特別的惡意。"},"stage":{"bg":"SS_SHADOW_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"죄수라 불리는 것도… 아마 마왕에게 밉보여서 잡혀 있었나봐.","JPN":"囚人って言われているのも……たぶん、魔王の恨みを買って捕まったんだと思う。","ENG":"I'm guessing that this prisoner was locked up because the Demon Lord didn't like her.","TWN":"之所以被稱為囚犯…可能是因為得罪了魔王才被抓住的吧。"},"stage":{"bg":"SS_SHADOW_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그렇게 악마의 하수인들을 피해 도망치다가 그 악마랑 마주쳤고, 루 언니가 단검을 써서 도망쳤어.","JPN":"それで、悪魔の手下から逃げてる最中にあの悪魔と出くわして、ルーお姉さんが短剣を使って逃げたの。","ENG":"Anyway, we were running away from the devil's henchmen when we ran into the devil himself, and that's when Ms. Lugh used the dagger to escape.","TWN":"之後在逃避魔鬼的手下途中遇到了那個魔鬼，露姊姊就用匕首逃脫了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"황금가지는… 결국 찾지 못했고.","JPN":"黄金の枝は……結局見つかってない。","ENG":"We couldn't find... where the Golden Branch was.","TWN":"我們沒能找到…金枝。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그래. 아쉬워할 거 없어.","JPN":"そう。でも残念に思う必要はないわ。","ENG":"I see. But no need to be discouraged.","TWN":"好了，沒什麼好遺憾的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너흴 잃게 되는 것보단 차라리 빈손이 나으니까. 잘 판단한 거야.","JPN":"アナタたちを失うくらいなら、手ぶらのほうがマシよ。いい判断だったわ。","ENG":"You did good. It is better for you to return empty-handed than not returning at all.","TWN":"比起失去你們，空手而歸也沒什麼不好。你們做了正確的判斷。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그 악마가 전부는 아니었어요.","JPN":"悪魔だけじゃありませんでした。","ENG":"The devil wasn't the only one there.","TWN":"那魔鬼並不只有一個。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"음? 전부가 아니라고?","JPN":"うん？　どういうこと？","ENG":"Hmm? There were more?","TWN":"嗯？不是全部？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그 악마가 말을 걸어오는 동안… 눈보라 너머에서 뭔가 다가오는 걸 느꼈거든요.","JPN":"その悪魔が話している時に……吹雪の向こうから何かが近づいてくるのを感じたんです。","ENG":"While he was talking to us... I could feel something getting closer from beyond the snowstorm.","TWN":"當他跟我說話的時候…我感覺有東西從暴風雪中接近。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그 정체를 확인하기 전에 도망쳐서 확인은 못 했지만요.","JPN":"姿を見る前に逃げてしまったので、確認はできませんでしたが。","ENG":"But we had to flee before we could get a better look.","TWN":"因為當時不得不離開，所以沒能確認它的身份。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"흐음.","JPN":"ふうん。","ENG":"Hmm.","TWN":"嗯嗯。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"악마를 눈앞에 두고도 느껴질 정도의 기운이라…","JPN":"悪魔を目の前にしても感じられるほどの気配、ね……","ENG":"An ominous entity that could be felt even with a devil in your presence...","TWN":"在魔鬼面前還能感覺到的氣息…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"아쉽지만, 그곳엔 다시 돌아가지 않는 편이 좋겠어.","JPN":"残念だけど、そこにはもう戻らない方がよさそうだわ。","ENG":"It is a shame, but it would be best not to go back there ever again.","TWN":"雖然很可惜，但最好不要再回到那裡了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐?! 그치만 황금가지는 아직 못 찾았는데?","JPN":"えっ！？　でも黄金の枝はまだ見つかってないよ？","ENG":"What?! But we haven't found the Golden Branch yet!","TWN":"什麼？！可是我們還沒找到金枝呢？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"마왕은 악마만큼이나 집요하거든.","JPN":"魔王は悪魔くらいしつこい相手よ。","ENG":"A Demon Lord is as persistent as a devil.","TWN":"魔王和魔鬼一樣執著。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너희가 다녀갔다는 걸 눈치챈 이상, 두 번은 그냥 넘어가지 않을 거야.","JPN":"アナタたちがそこにいたことに気付いた以上、二度は見逃してくれないはずよ。","ENG":"As long as they know you have been there, there will not be another time of going back.","TWN":"既然她已經察覺到你們來過，不會輕易放過你們第二次。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"윽…","JPN":"うっ……","ENG":"Ngh...","TWN":"呃…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"두 사람 모두 고생 많았어. 지쳤을 텐데 오늘은 돌아가서 편히 쉬도록 해.","JPN":"二人ともお疲れ様。疲れたでしょう、今日は帰ってゆっくり休みなさい。","ENG":"Good work, you two. Go get some rest as I am sure you are both exhausted.","TWN":"二位都辛苦了。你們一定很累了，今天就回去好好休息吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그럼… 포도 먹어도 돼?","JPN":"じゃあ……ブドウ食べてもいい？","ENG":"Then... can I have some grapes?","TWN":"那…可以吃葡萄嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"찾을 줄 알고 옆방 테이블에 준비해 뒀지.","JPN":"そう言うと思って、隣の部屋のテーブルに用意してあるわ。","ENG":"I have already prepared them on the table in the next room for you.","TWN":"就知道你會問，所以在隔壁房間的桌子上準備好了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아싸!","JPN":"やった！","ENG":"Yes!","TWN":"太好了！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"하하… 저럴 때보면 영락없는 어린애네요.","JPN":"はは……あんな姿を見ると、やっぱり子どもですね。","ENG":"Haha... She really seems like a little kid at times like this.","TWN":"哈哈…這種時候真像個小孩子。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_CONFUSION"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"곧 그루터기에 동절기가 오면 과일 구경도 힘들어질 거야.","JPN":"もうすぐ切り株が冬になったら、果物もなくなるはずよ。","ENG":"Once winter comes to the Stump, finding fruit will be difficult.","TWN":"很快冬季就要來了，到時候連水果都很難看到。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너도 같이 먹으렴.","JPN":"アナタも一緒に食べなさい。","ENG":"So you should have some as well.","TWN":"你也一起來吃吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"저기…","JPN":"あの……","ENG":"Um...","TWN":"那個…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"멀린 씨는 알고 계셨나요?","JPN":"マーリンさんは知っていたんですか？","ENG":"Did you know, Merlin?","TWN":"梅林，你知道嗎…？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"저희가 가는 곳이 어떤 장소인지.","JPN":"私たちの向かう場所がどんなところなのか。","ENG":"About the place we went to?","TWN":"我們去的那個地方是什麼地方？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"떠나기 전에도 말했지만, 우리가 가진 기술력으로 세상 반대편을 관측한 건 이번이 처음이야.","JPN":"出発する前にも言ったけれど、アタシの技術で世界の反対側を観測したのは今回が初めてよ。","ENG":"As I have told you before your departure, it is the first time we have observed the other side of the world with our technology.","TWN":"雖然在出發前也說明過，這是我們第一次用現有的技術觀測到世界的另一端…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그곳이 어떤 곳일지는 나도 추측만 할 뿐이었지.","JPN":"あそこがどんなところなのか、アタシも推測するだけだった。","ENG":"I merely assumed what kind of place it would be.","TWN":"那邊是什麼樣的地方，我能提供的也只有猜測。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그런데…","JPN":"でも……","ENG":"However...","TWN":"不過…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 표정을 보니, 너에겐 그곳의 풍경이 낯설지 않았던 모양이네.","JPN":"その顔を見ると、アナタにはあそこの景色に見覚えがあったようね。","ENG":"seeing your expression seems to tell me that it was familiar to you.","TWN":"看你的表情，那裡對你來說似乎並不陌生。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"제가 기억하던 고향의 모습이 새하얀 동토로 변해 있었어요.","JPN":"私が記憶している故郷が、真っ白な凍土に変わっていました。","ENG":"The hometown I remembered had turned into white gelid lands.","TWN":"我記憶中的故鄉變成了一片白茫茫的凍土。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"사람은 흔적도 찾아볼 수 없는 폐허였죠.","JPN":"人の跡はまったく見当たらない廃墟でしたよ。","ENG":"It was all in ruins without a single trace of people.","TWN":"曾經繁華的城市成了一片荒無人跡的廢墟。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…동토의 역병은 그 무엇도 피해갈 수 없어.","JPN":"……凍土の疫病は誰も避けられない。","ENG":"...Nothing can escape the grasp of the gelid lands' plague.","TWN":"…沒有什麼能逃得過凍土的瘟疫。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그게 언제가 되냐의 차이가 있을 뿐이지. 과거의 아발론도, 지금의 우리도 마찬가지고.","JPN":"時期に差があるだけ。過去のアバロンも、今のアタシたちも同じだわ。","ENG":"It is simply a matter of time. As it was for Avalon in the past, and the same for us now.","TWN":"只是時間早晚的問題。過去的阿瓦隆是這樣，現在的我們也是。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"엘리시온에선… 신민들 모두가 동토로부터 안전하다는 믿음을 갖고 살았어요.","JPN":"エリシオンでは……みんな凍土から守られる安全な場所だと信じて暮らしていました。","ENG":"In Elysion... everyone lived with the belief that they would be safe from the gelid lands.","TWN":"在艾利森…所有人都相信自己能免受凍土的侵害。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"고작 몇 년 사이에… 어떻게 그런 일이 벌어질 수 있는 거죠?","JPN":"たった数年で……どうしたらあんなことが起きるんですか？","ENG":"But in just a few years... how could something like this even happen?","TWN":"短短幾年間…怎麼會發生這樣的事？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"믿음이란 건 종종 걷잡을 수 없는 현실 앞에 무너져 내리곤 해.","JPN":"信仰というものは、時に大いなる現実の前では無力になるものだわ。","ENG":"Beliefs often collapse in the face of uncertain reality.","TWN":"信仰常常在無法控制的現實面前崩塌。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"아발론이 건재했던 시절에도, 다들 그런 믿음을 갖고 있었어.","JPN":"アバロンが健在だった時代にも、みんなそう信じていた。","ENG":"Even when Avalon still stood tall, everyone there also believed in something similar.","TWN":"在阿瓦隆還存在的時代，大家也有這樣的信仰。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"하지만 예언에 없던 역병이 온세상에 퍼지고, 마왕 타기리온이 강림하면서…","JPN":"でも予言にない疫病が世界中に広まり、魔王タギリオンが降臨してから……","ENG":"However, a plague unforeseen by prophecies spread throughout the world, and with the Demon Lord Thagirion's descent...","TWN":"但預言中沒有提到瘟疫會蔓延至整個世界，魔王塔基里翁會降臨…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"영원할 줄 알았던 아발론도 순식간에 겨울의 땅이 되었지.","JPN":"永遠に続くと信じられていたアバロンも、一瞬で冬の地になった。","ENG":"Avalon, which I thought would last for an eternity, abruptly turned into the gelid lands.","TWN":"人們以為會永遠不朽的阿瓦隆也瞬間變成了凍土。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"하지만…! 그건 까마득한 역사일 뿐이잖아요!","JPN":"でも……！　それは遠い昔の話でしょう！","ENG":"But...! That's just what's recorded in history!","TWN":"但是…！那只是遙遠的歷史！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"엘리시온은 마왕의 강림과는 아무런 관계도 없었어요!","JPN":"エリシオンは魔王の降臨とは何の関係もありませんでした！","ENG":"Elysion had nothing to do with the Demon Lord's descent!","TWN":"艾利森和魔王的降臨毫無關係！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"50년 전. 하룻동안 태양이 사라졌어.","JPN":"50年前。一日中、太陽が消えた。","ENG":"Fifty years ago. The sun disappeared for an entire day.","TWN":"50年前，太陽消失了一天。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"빛을 집어삼킨 하늘은 바라보는 사람을 실성케 했고, 지상엔 온갖 마물들이 날뛰며 피의 살육을 벌였지.","JPN":"光を飲み込んだ空は見上げる人を狂わせ、地上にはあらゆる魔物が暴れ血の殺戮を行ったわ。","ENG":"The lightless sky made anyone looking up lose their minds, and the earth was rampant with monsters and bloodshed.","TWN":"吞噬了光芒的天空，會讓任何膽敢凝視它的人發狂，地面上成了怪物血腥肆虐的樂園。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 전조는 마치, 마왕 타기리온이 강림했을 때와 같았어.","JPN":"その前兆はまさに、魔王タギリオンが降臨した時と同じだった。","ENG":"That omen was the same as when the Demon Lord Thagirion descended.","TWN":"那個預兆就像魔王塔基里翁又一次降臨了一樣。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네…? 50년 전이라고요?","JPN":"え……？　50年前？","ENG":"What...? Fifty years ago?","TWN":"可是…？50年前？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"하지만 그런 엄청난 일이 두번이나 있었단 얘긴… 처음 들어요. 역사서에서도 못 봤는데.","JPN":"でも、そんなとんでもないことが2回もあったって話……初めて聞きました。歴史書にも書かれていなかったはずです。","ENG":"But I've never heard of such a catastrophic event... happening twice. It wasn't in any historical records.","TWN":"又一次發生這種滅世般的天災…我是第一次聽說。歷史書上也沒看到過。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"들어본 적 없는 게 당연해.","JPN":"初めて聞いて当然よ。","ENG":"Of course, you never heard of it.","TWN":"沒聽說過是正常的。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"엘리시온이 몰락할 즈음, 넌 동토 한복판에서 잠들어 있었을 테니까.","JPN":"エリシオンが没落する頃、アナタは凍土の真ん中で眠っていたはずだから。","ENG":"Around the time Elysion was falling, you were asleep in the middle of the gelid lands.","TWN":"在艾利森沒落的時候，你應該是在凍土中沉睡著。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그건 말도 안 돼요!","JPN":"それはあり得ません！","ENG":"That can't be right!","TWN":"這不可能！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"전 엘리시온에서 태어났어요! 거기서 지내며 겪은 일들을 생생하게 기억한다고요!","JPN":"私はエリシオンで生まれました！　そこで暮らし経験したことを、はっきりと覚えています！","ENG":"I was born in Elysion! I still vividly remember the things I experienced there!","TWN":"我是在艾利森出生的！我清楚地記得在那裡經歷的一切！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"네 기억을 의심하는 게 아니야.","JPN":"アナタの記憶を疑っているわけではないわ。","ENG":"I am not doubting your memories.","TWN":"我不是在懷疑你的記憶。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"하지만 너도 자신이 눈 속에 얼마나 오랫동안 갇혀있었는지 셀 수는 없었겠지.","JPN":"でもアナタも自分がどれだけの間、雪の中に閉じ込められていたのか、数えることはできなかったはずよ。","ENG":"But it is also true that you have no idea how long you were trapped beneath the snow.","TWN":"但你也無法計算自己在冰雪中被困了多久吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"하지만…","JPN":"でも……","ENG":"But...","TWN":"可…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"제가 50년이 넘는 시간을 갇혀있었다니, 말도 안돼요.","JPN":"私が50年以上も閉じ込められていたなんて、あり得ません。","ENG":"Fifty years? That's ridiculous.","TWN":"我被困了超過50年…這是真的嗎…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그래.","JPN":"そう。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"제아무리 강한 성자도 50년을 눈 속에 갇혀 살아남는 건 불가능하지.","JPN":"いくら強い聖者だって、50年もの間雪の中に閉じ込められて生き残るのは不可能なの。","ENG":"Even the strongest of Helgons cannot survive trapped underneath the snow for fifty years.","TWN":"再強的聖者也不可能在雪中被困50年還能生還。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"하지만, 불가능한 얘기도 아니야.","JPN":"でも、例外があるわ。","ENG":"Yet, it is also not impossible.","TWN":"不，也不是完全不可能。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"널 요정이 지켜주고 있었다면 말이지.","JPN":"アナタを妖精が守ってくれていたなら、ね。","ENG":"If a fairy has been protecting you, that is.","TWN":"如果有精靈在保護你的話。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"요정… 이라고요?","JPN":"妖精……？","ENG":"A... fairy?","TWN":"精…靈？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};